import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  selectedRole: 'patient' | 'doctor' | 'admin' = 'patient';
  showPassword = false;

  constructor(private fb: FormBuilder, private router: Router) {}

  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      rememberMe: [false]
    });
  }

  selectRole(role: 'patient' | 'doctor' | 'admin'): void {
    this.selectedRole = role;
  }

  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  onSubmit(): void {
    if (this.loginForm.valid) {
      const email = this.loginForm.value.email;
      const password = this.loginForm.value.password;

      console.log('Trying to login as:', this.selectedRole);

      // الفحص بناءً على الـ Role المختار في الواجهة
      if (this.selectedRole === 'admin') {
        if (email === 'admin@hospital.com' && password === 'admin123') {
          // توجيه للوحة تحكم الأدمن بنجاح
          this.router.navigate(['/admin/dashboard']);
        } else {
          alert('بيانات دخول الأدمن خاطئة! استخدمي: admin@hospital.com / admin123');
        }
      } else {
        // لو مريض أو طبيب، وجهيه لصفحة الـ home مؤقتاً للتجربة
        this.router.navigate(['/home']);
      }

    } else {
      this.loginForm.markAllAsTouched();
    }
  }
}
